async findByInstallationAndKey({
  installationId,
  projectKey,
}: {
  installationId: string;
  projectKey: string;
}): Promise<IJiraProjectBase | null> {
  try {
    const result = await this.knexRead<IJiraProjectBase>(this.tableName)
      .where({ installation_id: installationId, project_key: projectKey })
      .first();
    return result ?? null;
  } catch (error) {
    this.logger.error(
      `Failed to find project ${projectKey} for installation ${installationId}: ${(error as Error).message}`,
    );
    throw error;
  }
}
```

