async processWebhookIssueEvent({
  installationDbId,
  payload,
}: {
  installationDbId: string;
  payload: IJiraWebhookIssuePayload;
}): Promise<void> {
  const installation = await this.installationModel.findById({ id: installationDbId });
  if (!installation) {
    this.logger.warn(`Installation ${installationDbId} not found for webhook event`);
    return;
  }

  const projectKey = payload.issue.key.split('-')[0] ?? payload.issue.key;
  const project = await this.projectModel.findByInstallationAndKey({
    installationId: installationDbId,
    projectKey,
  });

  if (!project) {
    this.logger.warn(`Project ${projectKey} not found for installation ${installationDbId}`);
    return;
  }

  const { issue } = payload;
  const savedIssues = await this.issueModel.upsertMany({
    issues: [
      {
        installation_id: installationDbId,
        project_id: project._id,
        issue_key: issue.key,
        issue_id: issue.id,
        issue_type: issue.fields.issuetype?.name ?? null,
        status: issue.fields.status?.name ?? null,
        priority: issue.fields.priority?.name ?? null,
        assignee_id: issue.fields.assignee?.accountId ?? null,
        reporter_id: issue.fields.reporter?.accountId ?? null,
        story_points: issue.fields.customfield_10016 ?? null,
        updated_at: new Date(issue.fields.updated),
        resolved_at: issue.fields.resolutiondate
          ? new Date(issue.fields.resolutiondate)
          : null,
      },
    ],
  });

  const savedIssue = savedIssues[0];
  if (payload.changelog && savedIssue) {
    await this.changelogModel.upsertMany({
      entries: payload.changelog.items.map((item) => ({
        issue_id: savedIssue._id,
        installation_id: installationDbId,
        jira_history_id: payload.changelog!.id,
        author_id: payload.user?.accountId ?? null,
        field: item.field,
        from_value: item.fromString,
        to_value: item.toString,
        changed_at: new Date(payload.timestamp),
      })),
    });
  }

  this.logger.debug(`Processed webhook ${payload.webhookEvent} for issue ${issue.key}`);
}
```

