import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger, UnauthorizedException } from '@nestjs/common';
import { Queue } from 'bullmq';

import { EnvConfigService } from '@modules/env-config/env-config.service';
import { IJiraWebhookIssuePayload } from '@modules/jira/types/jira-api.interface';
import { IProcessWebhookEventJob } from '@modules/jira/types/jira-sync.interface';

import { JIRA_WEBHOOK_SECRET } from '@constants/env-variables.constant';

const SUPPORTED_WEBHOOK_EVENTS = new Set(['jira:issue_created', 'jira:issue_updated']);

@Injectable()
export class JiraWebhookService {
  private readonly logger = new Logger(JiraWebhookService.name);

  constructor(
    private readonly configService: EnvConfigService,
    @InjectQueue('jira') private readonly jiraQueue: Queue,
  ) {}

  async handleEvent({
    secret,
    installationDbId,
    payload,
  }: {
    secret: string;
    installationDbId: string;
    payload: IJiraWebhookIssuePayload;
  }): Promise<void> {
    const expectedSecret = this.configService.get<string>({ key: JIRA_WEBHOOK_SECRET });
    if (secret !== expectedSecret) {
      throw new UnauthorizedException('Invalid webhook secret');
    }

    if (!SUPPORTED_WEBHOOK_EVENTS.has(payload.webhookEvent)) {
      this.logger.debug(`Skipping unsupported webhook event: ${payload.webhookEvent}`);
      return;
    }

    await this.jiraQueue.add(
      'process_webhook_event',
      { installationDbId, payload } satisfies IProcessWebhookEventJob,
      { attempts: 3, backoff: { type: 'exponential', delay: 5000 } },
    );

    this.logger.debug(
      `Queued process_webhook_event for installation ${installationDbId}, event ${payload.webhookEvent}`,
    );
  }
}
```

