```typescript
import { Injectable, Logger, NotFoundException } from '@nestjs/common';

import { GithubContributorModel } from '@modules/github/db/github-contributor.model';

@Injectable()
export class GithubIdentityService {
  private readonly logger = new Logger(GithubIdentityService.name);

  constructor(private readonly contributorModel: GithubContributorModel) {}

  async claimGithubIdentity({
    companyId,
    platformUserId,
    githubLogin,
  }: {
    companyId: string;
    platformUserId: string;
    githubLogin: string;
  }): Promise<void> {
    const contributors = await this.contributorModel.findByGithubLoginAcrossInstallations({
      companyId,
      githubLogin,
    });

    if (contributors.length === 0) {
      throw new NotFoundException(
        `No GitHub contributor found with login "${githubLogin}" in your company`,
      );
    }

    for (const contributor of contributors) {
      await this.contributorModel.linkPlatformUser({
        contributorId: contributor._id,
        platformUserId,
      });
    }

    this.logger.debug(
      `Linked ${String(contributors.length)} contributor records to platform user ${platformUserId}`,
    );
  }
}
