import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import { IJiraIdentityMappingBase } from '@modules/jira/types/jira-installation.interface';

import { TABLE_NAME_JIRA_IDENTITY_MAPPINGS } from '@constants/db.constant';

@Injectable()
export class JiraIdentityModel {
  private readonly logger = new Logger(JiraIdentityModel.name);
  private readonly tableName = TABLE_NAME_JIRA_IDENTITY_MAPPINGS;

  constructor(
    @InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
    @InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
  ) {}

  async upsert({
    installationId,
    jiraAccountId,
    platformUserId,
  }: {
    installationId: string;
    jiraAccountId: string;
    platformUserId: string;
  }): Promise<void> {
    try {
      await this.knexWrite<IJiraIdentityMappingBase>(this.tableName)
        .insert({
          _id: randomUUID(),
          installation_id: installationId,
          jira_account_id: jiraAccountId,
          platform_user_id: platformUserId,
          created_at: this.knexWrite.fn.now(),
          updated_at: this.knexWrite.fn.now(),
        })
        .onConflict(['installation_id', 'jira_account_id'])
        .merge(['platform_user_id', 'updated_at']);

      this.logger.debug(
        `Upserted identity mapping: ${jiraAccountId} → ${platformUserId}`,
      );
    } catch (error) {
      this.logger.error(
        `Failed to upsert identity mapping for ${jiraAccountId}: ${(error as Error).message}`,
      );
      throw error;
    }
  }

  async findByInstallationAndAccountId({
    installationId,
    jiraAccountId,
  }: {
    installationId: string;
    jiraAccountId: string;
  }): Promise<IJiraIdentityMappingBase | null> {
    try {
      const result = await this.knexRead<IJiraIdentityMappingBase>(this.tableName)
        .where({ installation_id: installationId, jira_account_id: jiraAccountId })
        .first();
      return result ?? null;
    } catch (error) {
      this.logger.error(
        `Failed to find identity mapping for ${jiraAccountId}: ${(error as Error).message}`,
      );
      throw error;
    }
  }
}
```

