import { Injectable, Logger, NotFoundException } from '@nestjs/common';

import { JiraIdentityModel } from '@modules/jira/db/jira-identity.model';
import { JiraInstallationModel } from '@modules/jira/db/jira-installations.model';

@Injectable()
export class JiraIdentityService {
  private readonly logger = new Logger(JiraIdentityService.name);

  constructor(
    private readonly identityModel: JiraIdentityModel,
    private readonly installationModel: JiraInstallationModel,
  ) {}

  async claimJiraIdentity({
    companyId,
    platformUserId,
    jiraAccountId,
  }: {
    companyId: string;
    platformUserId: string;
    jiraAccountId: string;
  }): Promise<void> {
    const installation = await this.installationModel.findByCompanyId({ companyId });

    if (!installation) {
      throw new NotFoundException(
        'No active Jira installation found for your company. Connect Jira first.',
      );
    }

    await this.identityModel.upsert({
      installationId: installation._id,
      jiraAccountId,
      platformUserId,
    });

    this.logger.debug(
      `Linked Jira account ${jiraAccountId} to platform user ${platformUserId}`,
    );
  }
}
