import { Processor, WorkerHost, OnWorkerEvent } from '@nestjs/bullmq';
import { Logger } from '@nestjs/common';
import { Job } from 'bullmq';

import { JiraSyncService } from '@modules/jira/jira-sync.service';
import {
	IDiscoverProjectsJob,
	IPollInstallationsJob,
	IProcessWebhookEventJob,
	ISyncProjectJob,
} from '@modules/jira/types/jira-sync.interface';

@Processor('jira')
export class JiraProcessor extends WorkerHost {
	private readonly logger = new Logger(JiraProcessor.name);

	constructor(private readonly syncService: JiraSyncService) {
		super();
	}

	// eslint-disable-next-line custom-rules/require-object-params
	async process(
		job: Job<
			| IDiscoverProjectsJob
			| ISyncProjectJob
			| IPollInstallationsJob
			| IProcessWebhookEventJob
		>,
	): Promise<void> {
		try {
			if (job.name === 'poll_installations') {
				await this.syncService.pollAllInstallations();
				return;
			}

			if (job.name === 'discover_projects') {
				const data = job.data as IDiscoverProjectsJob;
				await this.syncService.discoverProjects({
					installationDbId: data.installationDbId,
				});
				return;
			}

			if (job.name === 'sync_project') {
				const data = job.data as ISyncProjectJob;
				await this.syncService.syncProject({
					installationDbId: data.installationDbId,
					projectDbId: data.projectDbId,
					projectKey: data.projectKey,
				});
				return;
			}

			if (job.name === 'process_webhook_event') {
				const data = job.data as IProcessWebhookEventJob;
				await this.syncService.processWebhookIssueEvent({
					installationDbId: data.installationDbId,
					payload: data.payload,
				});
				return;

